import React, { useState, useRef } from "react";
import "./App.css";
import { array_of_mutants, Original, init, deletedTeams } from "./mutants";

/*
    App.js template for test-design
    Please use this as the text sample. It has a back button set maching with the test design style, etc...
*/

/*
                
    Komponens(function/class)  ->  JSX elemek  -> React -> DOM(HTML)
                       A       render                          |
           state változás <-------------------esemény----------      

*/

function App() {
  const [eredmeny, setEredmeny] = useState("-");
  const [killedMutants, setKilledMutants] = useState("-");
  var [testCaseNumber, setNumber] = useState(0);
  const [killed, setKilled] = useState([]);
  //const [wrongTests, setWrongTests] = useState("");
  const [wrongTests] = useState([]);
  var [printWrongTests, setPrintWrongTests] = useState("");
  var [missing, setMissing] = useState("");
  var [result, setResult] = useState("");
  const [mutant] = useState([]);
  const [wrongSolution, setWrongSolution] = useState(false);
  const [msg, setMessage] = useState("");
  const [members, setMembers] = useState(["", "", ""]);

  const xInput = useRef();
  const yInput = useRef();
  const zInput = useRef();
  const vInput = useRef();
  var [team, setTeam] = useState({
    teamName: "",
    members: ["", "", ""],
    complete: true,
    stolenMembers: [false, false, false],
    new: true,
    deleted: false,
  });

  //var actualTeam = { team: undefined, resultMessage: "", teams: undefined };
  var mutantTeam;

  function tryAgain() {
    for (var i = 0; i < array_of_mutants.length; i++) {
      killed[i] = false;
      mutant[i] = "";
    }
    setResult("");
    setMissing("");
    setNumber(0);
    setEredmeny(0);
    setWrongSolution(false);
    setMessage("");
    xInput.current.value = "";
    yInput.current.value = "";
    zInput.current.value = "";
    vInput.current.value = "";
    wrongTests[0] = "";
    init();
    actualTeam = { team: undefined, resultMessage: "", teams: undefined };
  }

  function nextTest() {
    xInput.current.value = "";
    yInput.current.value = "";
    zInput.current.value = "";
    vInput.current.value = "";
    wrongTests[0] = "";
    init();
    actualTeam = { team: undefined, resultMessage: "", teams: undefined };
  }

  function callFunctions() {
    //var y = yInput.current.value;
    //var z = zInput.current.value;
    //var v = vInput.current.value;
    //   var totalPrice = 0;
    // var mutantHikers;

    var killedMutants1 = "";
    team.teamName = xInput.current.value;
    team.members[0] = yInput.current.value;
    team.members[1] = zInput.current.value;
    team.members[2] = vInput.current.value;
    if (team.new) for (let i = 0; i <= 2; i++) team.stolenMembers[i] = false;
    //console.log("team: ", team);
    actualTeam = Original(team, 0);

    xInput.current.value = "";
    yInput.current.value = "";
    zInput.current.value = "";
    vInput.current.value = "";

    setEredmeny(actualTeam.resultMessage);
    var superfluousTest = true;
    if (
      !(
        team.teamName === "" &&
        team.members[0] === "" &&
        team.members[1] === "" &&
        team.members[2] === ""
      )
    ) {
      testCaseNumber++;
      for (var i = 0; i < array_of_mutants.length; i++) {
        if (!killed[i]) {
          mutantTeam = array_of_mutants[i](team, i + 1);
          mutant[i] = mutantTeam.mutant;
          if (
            actualTeam.resultMessage !== mutantTeam.resultMessage ||
            actualTeam.team.members[0] !== mutantTeam.team.members[0] ||
            actualTeam.team.members[1] !== mutantTeam.team.members[1] ||
            actualTeam.team.members[2] !== mutantTeam.team.members[2] ||
            mutantTeam.difference
          ) {
            var j = i + 1;
            killedMutants1 = killedMutants1 + j + " ";
            killed[i] = true;
            //       superfluousTest = false;
          }
        }
      }
      /*
      if (superfluousTest) {
        wrongTests[0] =
          "This test case is superfluous as it will not find any BVA-reated bug that haven't been found by your previous tests!";
        wrongSolution = true;
        console.log(" wrongSolution " + wrongSolution);
        //     console.log(wrongTests[0], ' superfluous')
      } else wrongTests[0] = "";
      */
    }
    setWrongSolution(wrongSolution);
    setKilledMutants(killedMutants1);
    setNumber(testCaseNumber);
    setMessage(actualTeam.resultMessage);
  }

  function printResult() {
    var optimalTestCaseNumber = 1; //!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
    var missingTests = false;
    var missedTestNumber = 0;
    missing = "";

    //callFunctions()
    for (var i = 0; i < array_of_mutants.length; i++) {
      if (!killed[i]) {
        missing = "Missing test: " + mutant[i];
        missingTests = true;
        missedTestNumber++;
        console.log("not killed new ", i);
      }
    }
    var ratio =
      100 - Math.round((missedTestNumber / array_of_mutants.length) * 100);
    printWrongTests = wrongTests;
    setPrintWrongTests(printWrongTests);
    //console.log("wrong " + wrongSolution);
    if (testCaseNumber === 0) {
      result = "Please write your test cases!";
    } else if (
      !missingTests &&
      !wrongSolution &&
      testCaseNumber > optimalTestCaseNumber
    ) {
      result = "Congratulation, you are very good at test design! "; //Our solution requires xx test cases.
      //   } else if (!missingTests && testCaseNumber === optimalTestCaseNumber) {
    } else if (!missingTests && !wrongSolution) {
      result = "Congratulation, you are very good at test design!";
    } else
      result =
        "You have found " + ratio + "% of the potential bugs. Try again! ";
    setResult(result);
    setMissing(missing);
  }

  function printResultAndInit() {
    printResult();
    //clearData()
  }

  function setInput(members) {
    yInput.current.value = members[0];
    zInput.current.value = members[1];
    vInput.current.value = members[2];
  }

  function handleChange(eventChange) {
    setMessage("");
    let currentTeamName = eventChange.target.value;
    let index = -1;
    if (actualTeam.teams !== undefined && currentTeamName !== "")
      index = actualTeam.teams.findIndex(
        (team) => team.teamName === currentTeamName
      );
    if (index > -1) {
      setInput(actualTeam.teams[index].members);
      //team = actualTeam.teams[index];
      team.new = false;
      //    if (actualTeam.teams[index].deleted) team.deleted = true;
      //  console.log("stolen2: ", actualTeam.teams[index].stolenMembers[2]);
      for (let i = 0; i <= 2; i++)
        team.stolenMembers[i] = actualTeam.teams[index].stolenMembers[i];
    } else {
      setInput(["", "", ""]);
      team.new = true;
      team.deleted = false;
    }
  }

  return (
    <div className="App">
      <header className="Back-header">
        <p class="Back">
          <a href="https://test-design.org/practical-exercises/">
            Back to Test Design Exercises
          </a>
        </p>
      </header>

      <header className="App-header">
        <p class="exercise">
          {" "}
          Read the specification below carefully. Add the test cases one by one.
          A test case ends with 'Next test'. You can continue adding test cases
          after 'Show my result'. <br />
          'Try again' starts a new test design session. &nbsp;&nbsp;You can use
          the <a href="https://cloud.harmony.ac/">Harmony tool</a> to make
          action-state test design and execute tests automatedly.
        </p>

        <p class="specification">
          <div style={{ textAlign: "center", fontSize: 20 }}>
            <b> Tour competition </b>
          </div>
          A tour competition application can handle registered teams as follows:{" "}
          <br />
          <b>R1</b> During the registration process a unique team name together
          with globally unique team members can be entered. A team has at least
          one and at most three members. The registration is activated when ‘Add
          team’ is pressed. <br />
          <b>R2</b> After entering an existing team name, missing team members
          can be added and existing team members can be deleted or modified.{" "}
          <br />
          <b>R3</b> Members of incomplete teams can be ‘stolen’, i.e., they can
          be added to another team during registration or modification, only if
          the 'thief' team is complete. <br />
          <b>R4</b> It is not allowed to construct a team only from 'stolen'
          members. <br />
          <b>R5</b> If all the team members have been 'stolen' from a team, it’s
          deleted automatically, and no new team can be registered with the
          deleted team’s name. <br />
          <b>R6</b> Stolen member cannot be modified only deleted. Stolen
          members can be further stolen from incomplete teams. <br />
          For simplicity, authentication is ignored. Thus, if you enter an
          existing team name, it's a team modification. No test to validate team
          uniqueness is possible. <br />
        </p>

        <p class="testcases">
          <span data-harmony-id="Missing test"> {missing}</span> <br />
          <span data-harmony-id="result">{result}</span> <br /> <br />
          Team:{" "}
          <input
            size="4"
            data-harmony-id="Team"
            ref={xInput}
            onChange={handleChange}
          />{" "}
          &nbsp;&nbsp;&nbsp;&nbsp;Member 1:{" "}
          <input size="4" data-harmony-id="Member1" ref={yInput} />
          &nbsp;&nbsp;&nbsp;&nbsp;Member 2:{" "}
          <span key={members[1]}>
            <input size="4" data-harmony-id="Member2" ref={zInput} />
          </span>
          &nbsp;&nbsp;&nbsp;&nbsp;Member 3:{" "}
          <input size="4" data-harmony-id="Member3" ref={vInput} />
          &nbsp;&nbsp;&nbsp;&nbsp;
          <button
            class="button"
            data-harmony-id="Add team"
            onClick={callFunctions}
          >
            {" "}
            Add team{" "}
          </button>{" "}
          <span
            data-harmony-id="Test case number"
            style={{ color: "mediumaquamarine" }}
          >
            Number of test steps: {testCaseNumber}
          </span>{" "}
          <br />
          <span data-harmony-id="message">
            {msg} <br />
          </span>
          <button class="button" data-harmony-id="Add test" onClick={nextTest}>
            {" "}
            Next test{" "}
          </button>
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          <button
            class="button"
            data-harmony-id="Stop"
            onClick={printResultAndInit}
          >
            {" "}
            Show my result{" "}
          </button>{" "}
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          <button class="button" data-harmony-id="Try again" onClick={tryAgain}>
            {" "}
            Try again{" "}
          </button>{" "}
          <br />
        </p>
      </header>
    </div>
  );
}

export default App;
var actualTeam = { team: undefined, resultMessage: "", teams: undefined };
